<script>
function rtError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_routing_process_failed', 'Routing failed to process.');?>);$('.error_data_delete').fadeIn();}
function esc(s){return String(s||'').replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c];});}
var lineNo=0;
function filters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),status:$('#filter_status').val(),plant:$('#filter_plant').val(),keyword:$('#filter_keyword').val()};}
function initMaterialSelect(el){if(!$.fn.select2)return;el.select2({width:'100%',dropdownParent:$('#modal_routing'),placeholder:<?=prod_js('production_search_fg_sfg', 'Search FG/SFG material...');?>,minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/routing/routing_action.php?act=material_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}}).on('select2:select',function(e){var d=e.params.data;$('#material_name').val(d.material_name||'');$('#base_uom').val(d.uom||'');});}
function initWorkCenterSelect(el){if(!$.fn.select2)return;el.select2({width:'100%',dropdownParent:$('#modal_routing'),placeholder:'Cari work center...',minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/routing/routing_action.php?act=work_center_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}}).on('select2:select',function(e){var d=e.params.data,tr=$(this).closest('tr');tr.find('input[name="work_center_id[]"]').val(d.work_center_id||'');tr.find('input[name="work_center_name[]"]').val(d.work_center_name||'');});}
function yn(name,val){return '<select name="'+name+'[]" class="form-control"><option value="N" '+(val!=='Y'?'selected':'')+'><?=prod_h('common_no', 'No');?></option><option value="Y" '+(val==='Y'?'selected':'')+'>Yes</option></select>';}
function appendLine(x){lineNo++;x=x||{};var rid='rt_line_'+lineNo,wcOpt=x.work_center_code?'<option value="'+esc(x.work_center_code)+'" selected>'+esc(x.work_center_code+' - '+(x.work_center_name||''))+'</option>':'';var opDefault=('0000'+(lineNo*10)).slice(-4);var row='<tr id="'+rid+'"><td class="text-center"><button type="button" class="btn btn-xs btn-danger btn-rt-remove-line"><i class="fa fa-trash"></i></button></td><td><input name="operation_no[]" class="form-control text-right" value="'+esc(x.operation_no||opDefault)+'" required></td><td><input name="operation_name[]" class="form-control" value="'+esc(x.operation_name||'')+'" required></td><td><select name="work_center_code[]" class="form-control rt-work-center" required>'+wcOpt+'</select><input type="hidden" name="work_center_id[]" value="'+esc(x.work_center_id||'')+'"><input type="hidden" name="work_center_name[]" value="'+esc(x.work_center_name||'')+'"></td><td><select name="control_key[]" class="form-control"><option value="PP01" '+((x.control_key||'PP01')==='PP01'?'selected':'')+'>PP01</option><option value="PP02" '+(x.control_key==='PP02'?'selected':'')+'>PP02</option><option value="PP03" '+(x.control_key==='PP03'?'selected':'')+'>PP03</option><option value="QM01" '+(x.control_key==='QM01'?'selected':'')+'>QM01</option></select></td><td><input name="standard_text[]" class="form-control" value="'+esc(x.standard_text||'')+'"></td><td><input type="number" step="0.00001" min="0" name="setup_time[]" class="form-control text-right" value="'+esc(x.setup_time||0)+'"></td><td><input type="number" step="0.00001" min="0" name="machine_time[]" class="form-control text-right" value="'+esc(x.machine_time||0)+'"></td><td><input type="number" step="0.00001" min="0" name="labor_time[]" class="form-control text-right" value="'+esc(x.labor_time||0)+'"></td><td><input type="number" step="0.00001" min="0" name="queue_time[]" class="form-control text-right" value="'+esc(x.queue_time||0)+'"></td><td><input type="number" step="0.00001" min="0" name="move_time[]" class="form-control text-right" value="'+esc(x.move_time||0)+'"></td><td><select name="time_uom[]" class="form-control"><option value="MIN" '+((x.time_uom||'MIN')==='MIN'?'selected':'')+'>MIN</option><option value="HOUR" '+(x.time_uom==='HOUR'?'selected':'')+'>HOUR</option><option value="DAY" '+(x.time_uom==='DAY'?'selected':'')+'>DAY</option></select></td><td><select name="capacity_category[]" class="form-control"><option value="MACHINE" '+((x.capacity_category||'MACHINE')==='MACHINE'?'selected':'')+'>Machine</option><option value="LABOR" '+(x.capacity_category==='LABOR'?'selected':'')+'>Labor</option><option value="SETUP" '+(x.capacity_category==='SETUP'?'selected':'')+'>Setup</option><option value="EXTERNAL" '+(x.capacity_category==='EXTERNAL'?'selected':'')+'>External</option></select></td><td><input type="number" step="0.00001" min="0" name="op_base_qty[]" class="form-control text-right" value="'+esc(x.base_qty||$('#base_qty').val()||1)+'"></td><td><input type="number" step="0.0001" min="0" max="100" name="yield_percent[]" class="form-control text-right" value="'+esc(x.yield_percent||100)+'"></td><td><input type="number" step="0.0001" min="0" name="scrap_percent[]" class="form-control text-right" value="'+esc(x.scrap_percent||0)+'"></td><td>'+yn('backflush',x.backflush)+'</td><td>'+yn('quality_check',x.quality_check)+'</td><td>'+yn('milestone',x.milestone)+'</td><td><input name="line_remarks[]" class="form-control" value="'+esc(x.remarks||'')+'"></td></tr>';$('#routing_lines').append(row);initWorkCenterSelect($('#'+rid+' .rt-work-center'));}
function loadNextRoutingNo(){ $('#routing_no').val('Loading...'); $.post('<?=base_admin();?>modul/routing/routing_action.php?act=next_no',{},function(r){ if(r.status==='good') $('#routing_no').val(r.routing_no||''); else $('#routing_no').val('Auto'); },'json').fail(function(){ $('#routing_no').val('Auto'); });}
function openForm(title,isEdit){lineNo=0;$('#form_routing')[0].reset();$('#routing_id,#material_name,#plant_code').val('');$('#routing_no').val('');$('#material_code').html('').trigger('change');$('#routing_lines').html('');$('#modal_routing .modal-title').text(title||'Create Routing');$('#routing_usage').val('PRODUCTION').trigger('change');$('#alternative_routing').val('01');$('#valid_from').val('<?=$today;?>');$('#base_qty').val('1');appendLine({operation_no:'0010',operation_name:'Preparation'});appendLine({operation_no:'0020',operation_name:'Production Process'});$('#modal_routing').modal({backdrop:'static',keyboard:false});if(!isEdit)loadNextRoutingNo();}
$(function(){if($.fn.datepicker){$('.rt-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_plant,#filter_status,#plant_id,#routing_usage').select2({width:'100%'});initMaterialSelect($('#material_code'));}
var dt=null;function reloadTable(resetPaging){if(dt&&dt.draw)dt.draw(resetPaging===false?false:undefined);}try{if($.fn.DataTable){dt=$('#dtb_routing').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[7,8],className:'text-right'},{width:'42px',targets:0},{width:'180px',targets:1}],ajax:{url:'<?=base_admin();?>modul/routing/routing_data.php',type:'post',data:function(d){$.extend(d,filters());},error:function(xhr){console.log(xhr.responseText);rtError(<?=prod_js('production_routing_load_failed', 'Routing data failed to load.');?>);}}});}}catch(e){console.error(e);rtError(<?=prod_js('production_routing_load_failed_create_available', 'Routing data failed to load. Create button remains available.');?>);}
$('#btn_open_routing').click(function(){openForm('Create Routing',false);});$('#plant_id').change(function(){$('#plant_code').val($('#plant_id option:selected').data('code')||'');});$('#btn_add_line').click(function(){appendLine();});$(document).on('click','.btn-rt-remove-line',function(){$(this).closest('tr').remove();});$('#btn_filter_routing').click(function(){reloadTable();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)reloadTable();});$('#btn_reset_routing').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_status,#filter_plant').val('').trigger('change');$('#filter_keyword').val('');reloadTable();});$('#btn_export_routing').click(function(){window.location='<?=base_admin();?>modul/routing/routing_action.php?act=excel&'+$.param(filters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$('#form_routing').submit(function(e){e.preventDefault();var btn=$(this).find('button[type=submit]');btn.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=prod_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/routing/routing_action.php?act=save',$(this).serialize(),function(r){if(r.status==='good'){$('#modal_routing').modal('hide');reloadTable(false);}else rtError(r.error_message);btn.prop('disabled',false).html('<i class="fa fa-save"></i> Save Draft');},'json').fail(function(xhr){rtError(xhr.responseText);btn.prop('disabled',false).html('<i class="fa fa-save"></i> Save Draft');});});
$(document).on('click','.btn-rt-detail',function(){$.post('<?=base_admin();?>modul/routing/routing_action.php?act=detail',{id:$(this).data('id')},function(html){$('#routing_detail_body').html(html);$('#modal_routing_detail').modal('show');});});
$(document).on('click','.btn-rt-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/routing/routing_action.php?act=get',{id:id},function(r){if(r.status!=='good'){rtError(r.error_message);return;}openForm('Edit Routing',true);var h=r.header||{};$('#routing_id').val(h.id);$('#routing_no').val(h.routing_no);$('#material_code').html('<option value="'+esc(h.material_code)+'" selected>'+esc(h.material_code+' - '+h.material_name)+'</option>').trigger('change');$('#material_name').val(h.material_name);$('#base_qty').val(h.base_qty);$('#base_uom').val(h.base_uom);$('#plant_id').val(h.plant_id||'').trigger('change');$('#plant_code').val(h.plant_code||'');$('#routing_usage').val(h.routing_usage||'PRODUCTION').trigger('change');$('#alternative_routing').val(h.alternative_routing||'01');$('#valid_from').val(h.valid_from);$('#valid_to').val(h.valid_to);$('#revision').val(h.revision);$('#change_number').val(h.change_number);$('#lot_size_from').val(h.lot_size_from);$('#lot_size_to').val(h.lot_size_to);$('#remarks').val(h.remarks);$('#routing_lines').html('');lineNo=0;(r.lines||[]).forEach(appendLine);},'json');});
function statusAction(act,id,no,title,input){var cfg={title:title,text:no,icon:'question',showCancelButton:true,confirmButtonText:title};if(input){cfg.input='text';cfg.inputLabel='Reason '+no;cfg.inputValidator=function(v){return !v?<?=prod_js('production_reason_required', 'Reason is required');?>:undefined;};}Swal.fire(cfg).then(function(x){if(!x.isConfirmed)return;var data={id:id};if(input)data.reason=x.value;$.post('<?=base_admin();?>modul/routing/routing_action.php?act='+act,data,function(r){if(r.status==='good')reloadTable(false);else rtError(r.error_message);},'json').fail(function(xhr){rtError(xhr.responseText);});});}
$(document).on('click','.btn-rt-release',function(){statusAction('release',$(this).data('id'),$(this).data('no'),'Release Routing');});$(document).on('click','.btn-rt-inactive',function(){statusAction('inactive',$(this).data('id'),$(this).data('no'),'Set Inactive',true);});$(document).on('click','.btn-rt-delete',function(){statusAction('delete',$(this).data('id'),$(this).data('no'),'Delete Draft');});
});
</script>
